sys_variable_value.value:
(function(outputs, steps, params, stepResult, assertEqual) {
    var parser = new CF_EmailParsingUtils();
    var input = '<table>' +
                '<tr><th>Item</th><th>Qty</th><th>Status</th></tr>' +
                '<tr><td>Laptop</td><td>1</td><td>Approved</td></tr>' +
                '<tr><td>Monitor</td><td>2</td><td>Pending</td></tr>' +
                '<tr><td>Keyboard</td><td>1</td><td>Approved</td></tr>' +
                '</table>';
    var result = parser.parseHtmlTables(input);
    if (!Array.isArray(result)) {
        stepResult.setOutputMessage('FAIL: Expected Array result. Got: ' + typeof result);
        stepResult.setFailed();
        return;
    }
    if (result.length !== 3) {
        stepResult.setOutputMessage('FAIL: Expected 3 data rows. Got: ' + result.length + '. Result: ' + JSON.stringify(result));
        stepResult.setFailed();
        return;
    }
    if (result[0]['Item'] !== 'Laptop' || result[0]['Status'] !== 'Approved') {
        stepResult.setOutputMessage('FAIL: Row 0 mismatch. Got: ' + JSON.stringify(result[0]));
        stepResult.setFailed();
        return;
    }
    if (result[1]['Item'] !== 'Monitor' || result[1]['Status'] !== 'Pending') {
        stepResult.setOutputMessage('FAIL: Row 1 mismatch. Got: ' + JSON.stringify(result[1]));
        stepResult.setFailed();
        return;
    }
    if (result[2]['Item'] !== 'Keyboard') {
        stepResult.setOutputMessage('FAIL: Row 2 mismatch. Got: ' + JSON.stringify(result[2]));
        stepResult.setFailed();
        return;
    }
    stepResult.setOutputMessage('PASS: Multi-row table parsed correctly. Result: ' + JSON.stringify(result));
    stepResult.setSuccess();
})(outputs, steps, params, stepResult, assertEqual);
